.note-preview-card-balanced {
  min-height: 17rem;
}

.note-preview-card-feature {
  min-height: 21rem;
}

.login-layout {
  grid-template-columns: minmax(0, 1.08fr) minmax(18rem, 0.92fr);
}

.link-manager-grid {
  align-items: start;
  grid-template-columns: minmax(0, 0.92fr) minmax(0, 1.08fr);
}

.note-editor-grid {
  grid-template-columns: minmax(0, 1.08fr) minmax(0, 0.92fr);
}

.note-editor-toolbar-controls {
  justify-content: flex-start;
}

.note-list-item {
  grid-template-columns: minmax(0, 1fr) auto;
}

.dashboard-note-item {
  grid-template-columns: minmax(0, 1.22fr) minmax(16.5rem, 1.08fr);
}

.dashboard-note-secondary {
  border-left: 1px solid rgba(148, 163, 184, 0.18);
  border-top: none;
  padding-left: 0.9rem;
  padding-top: 0;
}

.link-list-footer {
  align-items: center;
  grid-template-columns: minmax(0, 1fr) auto;
}

.sign-in-form input:focus {
  background: #ffffff;
  border-color: rgba(50, 72, 99, 0.34);
  box-shadow: 0 0 0 0.2rem rgba(50, 72, 99, 0.1);
  outline: none;
}

.note-textarea {
  min-height: clamp(18rem, 45vh, 22rem);
  resize: vertical;
}

.note-editor-workbench {
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.76), rgba(241, 245, 249, 0.94)),
    rgba(255, 255, 255, 0.88);
  border: 1px solid rgba(100, 116, 139, 0.18);
  border-radius: var(--radius-3);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.82),
    0 1rem 2.4rem rgba(15, 23, 42, 0.08);
  display: grid;
  gap: 0;
  overflow: hidden;
}

.note-editor-toolbar,
.note-editor-toolbar-header,
.note-editor-statusbar,
.note-editor-toolbar-copy,
.note-editor-toolbar-controls {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.65rem;
}

.note-editor-toolbar {
  border-bottom: 1px solid rgba(100, 116, 139, 0.14);
  gap: 0.85rem;
  padding: 0.9rem 1rem 0.95rem;
}

.note-editor-toolbar-header {
  justify-content: space-between;
}

.note-editor-toolbar-copy {
  align-items: baseline;
}

.note-editor-toolbar-copy strong {
  color: var(--accent-strong);
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  letter-spacing: 0.16em;
  text-transform: uppercase;
}

.note-editor-toolbar-copy .field-note {
  font-size: var(--text-sm);
}

.note-editor-statusbar {
  color: var(--ink-muted);
  font-family: var(--font-mono);
  font-size: 0.76rem;
  justify-content: flex-end;
  letter-spacing: 0.02em;
}

.note-editor-toolbar-controls {
  gap: 0.45rem;
}

.note-editor-tool {
  align-items: center;
  background: rgba(255, 255, 255, 0.78);
  border: 1px solid rgba(100, 116, 139, 0.16);
  border-radius: var(--radius-pill);
  color: var(--ink);
  cursor: pointer;
  display: inline-flex;
  font-family: var(--font-mono);
  font-size: 0.8rem;
  font-weight: 600;
  justify-content: center;
  min-height: 2.6rem;
  min-width: 2.6rem;
  padding: 0.55rem 0.7rem;
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease,
    transform 140ms ease,
    box-shadow 140ms ease;
}

.note-editor-tool:hover {
  background: rgba(255, 255, 255, 0.94);
  border-color: rgba(50, 72, 99, 0.2);
  color: var(--accent-strong);
}

.note-editor-tool:focus-visible {
  outline: 2px solid rgba(50, 72, 99, 0.28);
  outline-offset: 2px;
}

.note-editor-statusbar span {
  background: rgba(255, 255, 255, 0.74);
  border: 1px solid rgba(100, 116, 139, 0.12);
  border-radius: var(--radius-pill);
  min-height: 2rem;
  padding: 0.35rem 0.65rem;
}

.note-editor-surface {
  background:
    linear-gradient(180deg, rgba(248, 250, 252, 0.86), rgba(241, 245, 249, 0.98)),
    rgba(248, 250, 252, 0.96);
  display: grid;
  grid-template-columns: auto minmax(0, 1fr);
  min-height: clamp(21rem, 48vh, 28rem);
}

.note-editor-gutter {
  background:
    linear-gradient(180deg, rgba(226, 232, 240, 0.66), rgba(226, 232, 240, 0.38)),
    rgba(226, 232, 240, 0.72);
  border-right: 1px solid rgba(100, 116, 139, 0.14);
  color: var(--ink-faint);
  font-family: var(--font-mono);
  font-size: 0.76rem;
  letter-spacing: 0.03em;
  min-width: 3.45rem;
  overflow: hidden;
  padding: 1rem 0.55rem 1.15rem 0.7rem;
  text-align: right;
}

.note-editor-gutter-track {
  display: grid;
  gap: 0;
  line-height: 1.65;
}

.note-editor-stage {
  min-height: inherit;
  position: relative;
}

.note-editor-highlight,
.note-editor-input {
  font-family: var(--font-mono);
  font-size: 0.93rem;
  letter-spacing: 0;
  line-height: 1.65;
  margin: 0;
  min-height: inherit;
  padding: 1rem 1.1rem 1.15rem;
  tab-size: 2;
  white-space: pre-wrap;
  word-break: break-word;
}

.note-editor-highlight {
  color: var(--ink-soft);
  inset: 0;
  overflow: hidden;
  pointer-events: none;
  position: absolute;
}

.note-editor-highlight-content {
  display: block;
  min-height: 100%;
  transform: translate(calc(var(--editor-scroll-left) * -1), calc(var(--editor-scroll-top) * -1));
}

.note-editor-input {
  background: transparent;
  border: 0;
  border-radius: 0;
  caret-color: var(--accent-strong);
  color: transparent;
  display: block;
  min-width: 0;
  outline: none;
  overflow: auto;
  position: relative;
  resize: vertical;
  width: 100%;
  -webkit-text-fill-color: transparent;
}

.note-editor-input::selection {
  background: rgba(50, 72, 99, 0.18);
}

.note-editor-input:focus {
  background: transparent;
  box-shadow: none;
}

.note-editor-workbench:focus-within {
  border-color: rgba(50, 72, 99, 0.24);
